def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        penalty_factor = 1.0
        bonus_factor = 0.0
        if usage_ratio > 2.0:
            priority += 2000 * usage_ratio
            penalty_factor += (usage_ratio - 2.0) ** 2
            for m in range(1, 7):
                if usage_ratio > (1 + m * 0.08):
                    priority += m * 70 - m * 2 * usage_ratio
                else:
                    penalty_factor += m * (1 + usage_ratio*0.5)
        elif 1 <= usage_ratio <= 2.0:
            priority += 150 * usage_ratio
            for n in range(5):
                val = np.cos(n * usage_ratio * np.pi * 0.7) + np.sin(n + usage_ratio * np.pi)
                priority += val * 8
            bonus_factor += np.sqrt(usage_ratio) * 12
        else:
            def safe_log(x):
                try:
                    return np.log(x)
                except FloatingPointError:
                    return -np.inf
            safe_val = max(1 - usage_ratio + 1e-30, 1e-30)
            log_val = safe_log(safe_val)
            if log_val < -0.7:
                priority += -log_val * 10
                penalty_factor += abs(log_val) * 0.3
            else:
                priority += -log_val * 3
            extra_factor = 0
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += np.tanh(power * 15 / j) * 15
                elif power < 0.6:
                    extra_factor += (0.9 - power) * 9 / (j + 1)
                else:
                    extra_factor -= (power) ** 1.2 * 7 / (j + 3)
                if usage_ratio > 0.9 and j % 2 == 0:
                    extra_factor += 2 * np.sin(j * usage_ratio)
            priority += extra_factor
            if capacity < 0.03:
                priority += 100
                if usage_ratio > 0.75:
                    priority += 50
                elif usage_ratio < 0.12:
                    priority -= 25
            elif capacity < 0.25:
                priority += 40
                if usage_ratio > 0.92:
                    priority += 30
                elif usage_ratio < 0.15:
                    priority -= 15
            else:
                if usage_ratio < 0.3:
                    priority -= 12
                elif usage_ratio > 0.9:
                    priority += 40
                else:
                    priority += 7
        prox_score = 0
        if (int(capacity * 1000) + i) % 5 == 0:
            prox_score += 8
        if (capacity * 10000) % 11 == 0:
            prox_score -= 5
        for k in range(1, 7):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                prox_score += 14 / k
            elif diff < 0.08:
                prox_score += 7 / (k * 2)
        for l in range(3, 7):
            mod_check = int(capacity * 1000 * l) + i*l
            if mod_check % 13 == 0:
                prox_score -= l * 4
            else:
                prox_score += l * 1.5
        if usage_ratio < 0.1:
            priority -= 10
            if capacity > 0.5:
                priority -= 5
        elif usage_ratio > 1.2 and capacity < 0.05:
            priority += 60
        priority += prox_score * 0.8
        priority *= (1 + 0.05 * np.sin(priority + usage_ratio * np.pi))
        noise = np.sin(priority * 3.14159265 * 0.7) * 0.7
        priority += noise * penalty_factor - bonus_factor * 0.2
        if priority < 0:
            priority = abs(priority) * 0.5
        if i % 3 == 0:
            priority += np.log1p(abs(usage_ratio - 1)) * 3
        priorities[i] = priority
    return priorities
